// SplitConfigurationRule defines model for SplitConfigurationRule.
type SplitConfigurationRule struct {
	// CardRegion The card region condition that determines whether the [split logic](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic) applies to the transaction.
	//
	// > This condition is in pilot phase, and not yet available for all platforms.
	//
	// Possible values:
	// * **domestic**: The card issuer and the store where the transaction is processed are registered in the same country.
	// * **international**: The card issuer and the store where the transaction is processed are registered in different countries or regions. Includes all **interRegional** and **intraRegional** transactions.
	// * **interRegional**: The card issuer and the store where the transaction is processed are registered in different regions.
	// * **intraRegional**: The card issuer and the store where the transaction is processed are registered in different countries, but in the same region.
	// * **intraEEA**: The card issuer and the store where the transaction is processed are registered in different countries, but in the European Economic Area (EEA).
	// * **ANY**: Applies to all transactions, regardless of the processing and issuing country/region.
	CardRegion SplitConfigurationRuleCardRegion `json:"cardRegion,omitempty"`

	// Currency The currency condition that defines whether the split logic applies.
	// Its value must be a three-character [ISO currency code](https://en.wikipedia.org/wiki/ISO_4217).
	Currency string `json:"currency"`

	// FundingSource The funding source of the payment method.
	//
	// Possible values:
	// * **credit**
	// * **debit**
	// * **prepaid**
	// * **deferred_debit**
	// * **charged**
	// * **ANY**
	FundingSource SplitConfigurationRuleFundingSource `json:"fundingSource"`

	// PaymentMethod The payment method condition that defines whether the split logic applies.
	//
	// Possible values:
	// * [Payment method variant](https://docs.adyen.com/development-resources/paymentmethodvariant): Apply the split logic for a specific payment method.
	// * **ANY**: Apply the split logic for all available payment methods.
	PaymentMethod string `json:"paymentMethod"`

	// RuleId The unique identifier of the split configuration rule.
	RuleId string `json:"ruleId,omitempty"`

	// ShopperInteraction The sales channel condition that defines whether the split logic applies.
	//
	// Possible values:
	// * **Ecommerce**: Online transactions where the cardholder is present.
	// * **ContAuth**: Card on file and/or subscription transactions, where the cardholder is known to the merchant (returning customer).
	// * **Moto**: Mail-order and telephone-order transactions where the customer is in contact with the merchant via email or telephone.
	// * **POS**: Point-of-sale transactions where the customer is physically present to make a payment using a secure payment terminal.
	// * **ANY**: All sales channels.
	ShopperInteraction SplitConfigurationRuleShopperInteraction `json:"shopperInteraction"`

	// SplitLogic Contains the split logic that is applied if the rule conditions are met.
	SplitLogic SplitConfigurationLogic `json:"splitLogic"`
}

