// UpdateSplitConfigurationLogicRequest defines model for UpdateSplitConfigurationLogicRequest.
type UpdateSplitConfigurationLogicRequest struct {
	// AcquiringFees Deducts the acquiring fees (the aggregated amount of interchange and scheme fee) from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	AcquiringFees UpdateSplitConfigurationLogicRequestAcquiringFees `json:"acquiringFees,omitempty"`

	// AdditionalCommission Defines whether to book an additional commission for payments to your user's balance account. The commission amount can be defined as a fixed amount (specified in minor units), a percentage (specified in basis points), or both.
	AdditionalCommission AdditionalCommission `json:"additionalCommission,omitempty"`

	// AdyenCommission Deducts the transaction fee due to Adyen under [blended rates](https://www.adyen.com/knowledge-hub/guides/payments-training-guide/get-the-best-from-your-card-processing) from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	AdyenCommission UpdateSplitConfigurationLogicRequestAdyenCommission `json:"adyenCommission,omitempty"`

	// AdyenFees Deducts the fees due to Adyen (markup or commission) from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	AdyenFees UpdateSplitConfigurationLogicRequestAdyenFees `json:"adyenFees,omitempty"`

	// AdyenMarkup Deducts the transaction fee due to Adyen under [Interchange ++ pricing](https://www.adyen.com/what-is-interchange) from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	AdyenMarkup UpdateSplitConfigurationLogicRequestAdyenMarkup `json:"adyenMarkup,omitempty"`

	// Chargeback Specifies how and from which balance account(s) to deduct the chargeback amount.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**, **deductAccordingToSplitRatio**.
	Chargeback UpdateSplitConfigurationLogicRequestChargeback `json:"chargeback,omitempty"`

	// ChargebackCostAllocation Deducts the chargeback costs from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**
	ChargebackCostAllocation UpdateSplitConfigurationLogicRequestChargebackCostAllocation `json:"chargebackCostAllocation,omitempty"`

	// Commission Defines your platform's commission for the processed payments as a fixed amount (specified in minor units), a percentage (specified in basis points), or both. The commission is booked to your platform's liable balance account.
	Commission Commission `json:"commission"`

	// Interchange Deducts the interchange fee from specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	Interchange UpdateSplitConfigurationLogicRequestInterchange `json:"interchange,omitempty"`

	// PaymentFee Deducts all transaction fees incurred by the payment from the specified balance account. The transaction fees include the acquiring fees (interchange and scheme fee), and the fees due to Adyen (markup or commission). You can book any and all these fees to different balance account by specifying other transaction fee parameters in your split configuration profile:
	//
	// - [`adyenCommission`](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic-adyenCommission): The transaction fee due to Adyen under [blended rates](https://www.adyen.com/knowledge-hub/interchange-fees-explained#interchange-vs-blended).
	// - [`adyenMarkup`](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic-adyenMarkup): The transaction fee due to Adyen under [Interchange ++ pricing](https://www.adyen.com/knowledge-hub/interchange-fees-explained#interchange-vs-blended).
	// - [`schemeFee`](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic-schemeFee): The fee paid to the card scheme for using their network.
	// - [`interchange`](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic-interchange): The fee paid to the issuer for each payment transaction made with the card network.
	// - [`adyenFees`](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic-adyenFees): The aggregated amount of Adyen's commission and markup.
	// - [`acquiringFees`](https://docs.adyen.com/api-explorer/Management/latest/post/merchants/(merchantId)/splitConfigurations#request-rules-splitLogic-acquiringFees): The aggregated amount of the interchange and scheme fees.
	//
	// If you don't include at least one transaction fee type in the `splitLogic` object, Adyen updates the payment request with the `paymentFee` parameter, booking all transaction fees to your platform's liable balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	PaymentFee UpdateSplitConfigurationLogicRequestPaymentFee `json:"paymentFee,omitempty"`

	// Refund Specifies how and from which balance account(s) to deduct the refund amount.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**, **deductAccordingToSplitRatio**
	Refund UpdateSplitConfigurationLogicRequestRefund `json:"refund,omitempty"`

	// RefundCostAllocation Deducts the refund costs from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**
	RefundCostAllocation UpdateSplitConfigurationLogicRequestRefundCostAllocation `json:"refundCostAllocation,omitempty"`

	// Remainder Books the amount left over after currency conversion to the specified balance account.
	//
	// Possible values: **addToLiableAccount**, **addToOneBalanceAccount**.
	Remainder UpdateSplitConfigurationLogicRequestRemainder `json:"remainder,omitempty"`

	// SchemeFee Deducts the scheme fee from the specified balance account.
	//
	// Possible values: **deductFromLiableAccount**, **deductFromOneBalanceAccount**.
	SchemeFee UpdateSplitConfigurationLogicRequestSchemeFee `json:"schemeFee,omitempty"`

	// SplitLogicId Unique identifier of the collection of split instructions that are applied when the rule conditions are met.
	SplitLogicId string `json:"splitLogicId,omitempty"`

	// Surcharge Books the surcharge amount to the specified balance account.
	//
	// Possible values: **addToLiableAccount**, **addToOneBalanceAccount**
	Surcharge UpdateSplitConfigurationLogicRequestSurcharge `json:"surcharge,omitempty"`

	// Tip Books the tips (gratuity) to the specified balance account.
	//
	// Possible values: **addToLiableAccount**, **addToOneBalanceAccount**.
	Tip UpdateSplitConfigurationLogicRequestTip `json:"tip,omitempty"`
}

